package "java" {
  package "time" {
    class "LocalDate" as LocalDate << (C,green) >>
  }
  package "util" {
    interface "List" as List << (I,purple) >>
    class "URL" as URL << (C,green) >>
  }
}

package "org" {
  package "springframework" {
    package "hateoas" {
      class "RepresentationModel" as RepresentationModel << (C,green) >>
    }
  }
}

package "com" {
  package "acme" {
    package "filiale" {
      package "rest" {
        class "KundeModel" as KundeModel << (C,green) >> {
          <<entity>>
          name : String
          email : String
          kategorie: Int
          hasNewsletter: Boolean
          geburtsdatum: LocalDate
          homepage: URL
          geschlecht: GeschlechtType
          familienstand: FamilienstandType
          interessen: List<InteresseType>
        }
      }
      package "entity" {
        class "Kunde" as Kunde << (C,green) >>
        class "Umsatz" as Umsatz << (C,green) >>
        class "Adresse" as Adresse << (C,green) >>
        enum "GeschlechtType" as GeschlechtType << (E,red) >>
        enum "FamilienstandType" as FamilienstandType << (E,red) >>
        enum "InteresseType" as InteresseType << (E,red) >>
      }
    }
  }
}

KundeModel --|> RepresentationModel
KundeModel ..> LocalDate
KundeModel ..> List
KundeModel ..> URL
KundeModel ..> Kunde
KundeModel "0..1" *-- "umsatz" Umsatz
KundeModel "1" *-- "adresse" Adresse
KundeModel ..> GeschlechtType
KundeModel ..> FamilienstandType
KundeModel ..> InteresseType

note bottom of KundeModel: (c) Jürgen Zimmermann
@enduml
